function BtnChrome({ children, onClick, href }) {
  const [hov, setHov] = useState(false);
  const s = {
    background: `linear-gradient(135deg, ${theme.cr5}, ${theme.cr7})`,
    color: theme.bg0, border: "none", padding: ".85rem 2rem",
    fontFamily: "'Raleway',sans-serif", fontSize: ".67rem", letterSpacing: ".24em",
    textTransform: "uppercase", cursor: "pointer", fontWeight: 700,
    transition: "all .3s", textDecoration: "none", display: "inline-block",
    boxShadow: hov ? "0 8px 30px rgba(180,200,228,.22)" : "none",
    transform: hov ? "translateY(-2px)" : "none",
  };
  if (href) return <a href={href} style={s} onMouseEnter={() => setHov(true)} onMouseLeave={() => setHov(false)}>{children}</a>;
  return <button style={s} onClick={onClick} onMouseEnter={() => setHov(true)} onMouseLeave={() => setHov(false)}>{children}</button>;
}

function BtnGhost({ children, onClick, href }) {
  const [hov, setHov] = useState(false);
  const s = {
    background: hov ? "rgba(180,200,228,.04)" : "transparent",
    border: `1px solid ${hov ? theme.cr5 : theme.bdAct}`,
    color: hov ? theme.cr7 : theme.cr5,
    padding: ".85rem 2rem",
    fontFamily: "'Raleway',sans-serif", fontSize: ".67rem", letterSpacing: ".24em",
    textTransform: "uppercase", cursor: "pointer", fontWeight: 400,
    transition: "all .3s", textDecoration: "none", display: "inline-block",
  };
  if (href) return <a href={href} style={s} onMouseEnter={() => setHov(true)} onMouseLeave={() => setHov(false)}>{children}</a>;
  return <button style={s} onClick={onClick} onMouseEnter={() => setHov(true)} onMouseLeave={() => setHov(false)}>{children}</button>;
}

